/**
 * 30-second safety video — client-safe shapes + WebVTT track selection
 * (plan §5.6 "안전 비디오 (WebVTT 다중 트랙)", §7 Phase 4).
 *
 * Deliberately NOT the poiVideos contract. A POI short is one narrated MP4 per
 * language with burned-in subtitles; the safety film is the opposite by design
 * (§5.6.1): ONE silent pictogram render plus ten WebVTT subtitle tracks, so a
 * new language costs a text file rather than a re-render, and the browser does
 * the rendering natively.
 *
 * The tracks are static files under `public/videos/safety-intro-30s/subtitles/`
 * generated by `npm run safety:vtt` from lib/video-automation/safetyScript.ts.
 * They exist and serve today; only the MP4 is a human deliverable. Until an
 * admin approves a `poi_videos` row with kind='safety', `fetchSafetyVideoCard`
 * returns null and the safety card is complete as text — no placeholder player.
 */

import type { RoomLocale } from '@/lib/tour-room/snapshot';

/** Sentinel `poi_videos.poi_key` for the (POI-less) safety render. */
export const SAFETY_VIDEO_POI_KEY = '__safety_intro_30s';
/** ISO 639-2 "mul" — the render itself is silent, so it has no one language. */
export const SAFETY_VIDEO_LANGUAGE = 'mul';

export const SAFETY_SUBTITLE_BASE = '/videos/safety-intro-30s/subtitles';

/** The 10 subtitle languages the plan commits to (§5.6.2). */
export const SAFETY_SUBTITLE_LOCALES = [
  'en',
  'ko',
  'zh-TW',
  'zh-CN',
  'ja',
  'es',
  'de',
  'fr',
  'it',
  'ru',
] as const;

export type SafetySubtitleLocale = (typeof SAFETY_SUBTITLE_LOCALES)[number];

/** `<track label>` — each language named in its own language (browser UI). */
export const SAFETY_SUBTITLE_LABELS: Record<SafetySubtitleLocale, string> = {
  en: 'English',
  ko: '한국어',
  'zh-TW': '繁體中文',
  'zh-CN': '简体中文',
  ja: '日本語',
  es: 'Español',
  de: 'Deutsch',
  fr: 'Français',
  it: 'Italiano',
  ru: 'Русский',
};

export interface SafetySubtitleTrack {
  srclang: SafetySubtitleLocale;
  label: string;
  src: string;
}

export const SAFETY_SUBTITLE_TRACKS: readonly SafetySubtitleTrack[] = SAFETY_SUBTITLE_LOCALES.map(
  (locale) => ({
    srclang: locale,
    label: SAFETY_SUBTITLE_LABELS[locale],
    src: `${SAFETY_SUBTITLE_BASE}/${locale}.vtt`,
  }),
);

/** Rides in `briefing_safety` metadata as `video_card`. */
export interface SafetyVideoCardMeta {
  video_url: string;
  poster_url: string | null;
  duration_seconds: number | null;
  /** Copied into metadata so an old capsule keeps rendering the tracks it shipped with. */
  tracks: SafetySubtitleTrack[];
}

export function isSafetyVideoMeta(value: unknown): value is SafetyVideoCardMeta {
  if (!value || typeof value !== 'object') return false;
  const meta = value as SafetyVideoCardMeta;
  return typeof meta.video_url === 'string' && meta.video_url.trim() !== '';
}

/** Raw chat locale ('pt-BR', 'zh_Hant') → a track we actually ship, or null. */
export function matchSafetySubtitleLocale(raw: unknown): SafetySubtitleLocale | null {
  if (typeof raw !== 'string') return null;
  const value = raw.trim().replace(/_/g, '-');
  if (!value) return null;
  const exact = SAFETY_SUBTITLE_LOCALES.find((l) => l.toLowerCase() === value.toLowerCase());
  if (exact) return exact;
  const base = value.split('-')[0].toLowerCase();
  const region = value.split('-')[1]?.toUpperCase() ?? '';
  if (base === 'zh') {
    // Hant/TW/HK/MO read Traditional; everything else Simplified.
    return region === 'TW' || region === 'HK' || region === 'MO' || /hant/i.test(value)
      ? 'zh-TW'
      : 'zh-CN';
  }
  const byBase = SAFETY_SUBTITLE_LOCALES.find((l) => l.split('-')[0] === base);
  return byBase ?? null;
}

/**
 * Which track carries `default` for this viewer: their own chat language when
 * we ship it (the language-agnostic bridge already knows it), else the folded
 * room locale, else English.
 */
export function defaultSafetySubtitleLocale(
  roomLocale: RoomLocale,
  preferredLocale?: string | null,
): SafetySubtitleLocale {
  return (
    matchSafetySubtitleLocale(preferredLocale) ?? matchSafetySubtitleLocale(roomLocale) ?? 'en'
  );
}
